import type {
    ConsumptionEntry,
    DailyNutritionSummary,
    FoodItem,
    NewConsumptionEntry,
} from '../types/health.js';
import type { DbDriver } from '../types/db.js';
import { NOOP_LOGGER, type RepoLogger } from '../types/logger.js';
import { uuidv7 } from '../utils/uuid.js';
import { resolveAppTimeZone } from '../utils/app-time.js';
import { NotFoundError } from '../api/response-helpers.js';

const COLUMNS = `
    id, date, meal_type, food_item_id, amount,
    calories, protein_g, carbs_g, fat_g, fiber_g, sugar_g, sodium_mg,
    source_meal_id, meal_occurrence_id, consumed_at, created_at, updated_at
`;

// How many recent consumption rows feed the default-serving recompute (story 117).
// Small enough to react to habit shifts within a couple of weeks; large enough
// that one outlier among recent logs is dampened.
const DEFAULT_SERVING_WINDOW = 10;

function median(values: readonly number[]): number {
    const sorted = [...values].sort((a, b) => a - b);
    const n = sorted.length;
    const mid = Math.floor(n / 2);
    return n % 2 === 1 ? sorted[mid] : (sorted[mid - 1] + sorted[mid]) / 2;
}

/**
 * INSERT one consumption entry and recompute its food item's
 * `default_serving_amount` (story 117). Does **not** open a transaction —
 * the caller is responsible. Used by:
 *   - `consumption.create` (wraps a single call in its own BEGIN/COMMIT).
 *   - `meals.logMeal` (wraps N calls in one BEGIN/COMMIT — story 077).
 *
 * Sharing this helper keeps the INSERT SQL and recompute trigger in exactly
 * one place; both code paths funnel through here.
 */
export async function insertConsumptionEntryAndRecompute(
    driver: DbDriver,
    entry: NewConsumptionEntry,
): Promise<string> {
    const id = uuidv7();
    await driver.execute(
        `
            INSERT INTO consumption_entries (
                id, date, meal_type, food_item_id, amount,
                calories, protein_g, carbs_g, fat_g, fiber_g, sugar_g, sodium_mg,
                source_meal_id, meal_occurrence_id, consumed_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        `,
        id,
        entry.date,
        entry.meal_type,
        entry.food_item_id,
        entry.amount,
        entry.calories ?? null,
        entry.protein_g ?? null,
        entry.carbs_g ?? null,
        entry.fat_g ?? null,
        entry.fiber_g ?? null,
        entry.sugar_g ?? null,
        entry.sodium_mg ?? null,
        entry.source_meal_id ?? null,
        entry.meal_occurrence_id ?? null,
        entry.consumed_at ?? null,
    );
    await recomputeDefaultServingAmount(driver, entry.food_item_id);
    return id;
}

/**
 * Recompute `food_items.default_serving_amount` from the most recent
 * consumption entries for that food item. Story 117: median of the last 10,
 * with last-used-wins for ≤2 entries (a 1- or 2-sample median is just the
 * value(s) itself, and last-used reacts faster). With zero entries left
 * (e.g. last delete) the column is left untouched — there is no signal to
 * reset to.
 */
export async function recomputeDefaultServingAmount(driver: DbDriver, foodItemId: string): Promise<void> {
    // Order by SQLite rowid: it is always monotonically increasing on INSERT,
    // unlike created_at (1-second resolution from datetime('now')) and UUIDv7
    // ids (which can be non-monotonic within the same ms). rowid is cheap and
    // never lies about insertion order on this table.
    const rows = await driver.query<{ amount: number }>(
        `SELECT amount FROM consumption_entries
         WHERE food_item_id = ?
         ORDER BY rowid DESC
         LIMIT ${DEFAULT_SERVING_WINDOW}`,
        foodItemId,
    );
    if (rows.length === 0) return;
    const next = rows.length <= 2 ? rows[0].amount : median(rows.map((r) => r.amount));
    await driver.execute(
        `UPDATE food_items SET default_serving_amount = ?, updated_at = datetime('now') WHERE id = ?`,
        next,
        foodItemId,
    );
}

/**
 * Compute snapshot macros for a consumption entry from the food item's per-base
 * density and the amount consumed. Per-base values are relative to
 * `food_item.base_amount` in `food_item.base_unit`.
 *
 * Returns one number (or null) per nutrient column. Null when either the
 * per-base value or the base_amount is missing/zero — fail-loud over guessing.
 */
export function computeSnapshotMacros(item: Pick<FoodItem,
    'base_amount' | 'calories_per_base' | 'protein_g_per_base' | 'carbs_g_per_base' | 'fat_g_per_base' | 'fiber_g_per_base' | 'sugar_g_per_base' | 'sodium_mg_per_base'>,
    amount: number,
): {
    calories: number | null;
    protein_g: number | null;
    carbs_g: number | null;
    fat_g: number | null;
    fiber_g: number | null;
    sugar_g: number | null;
    sodium_mg: number | null;
} {
    const base = item.base_amount;
    if (!Number.isFinite(base) || base <= 0 || !Number.isFinite(amount)) {
        return {
            calories: null, protein_g: null, carbs_g: null, fat_g: null,
            fiber_g: null, sugar_g: null, sodium_mg: null,
        };
    }
    const factor = amount / base;
    const scale = (per: number | undefined | null): number | null => {
        if (typeof per !== 'number' || !Number.isFinite(per)) return null;
        return per * factor;
    };
    return {
        calories: scale(item.calories_per_base),
        protein_g: scale(item.protein_g_per_base),
        carbs_g: scale(item.carbs_g_per_base),
        fat_g: scale(item.fat_g_per_base),
        fiber_g: scale(item.fiber_g_per_base),
        sugar_g: scale(item.sugar_g_per_base),
        sodium_mg: scale(item.sodium_mg_per_base),
    };
}

export interface ConsumptionRepositoryOptions {
    log?: RepoLogger;
}

export function createConsumptionRepository(driver: DbDriver, options: ConsumptionRepositoryOptions = {}) {
    const log = options.log ?? NOOP_LOGGER;
    const repository = {
        async findById(id: string): Promise<ConsumptionEntry | null> {
            log.debug('consumption.findById', { id });
            return driver.queryOne<ConsumptionEntry>(`SELECT ${COLUMNS} FROM consumption_entries WHERE id = ?`, [id]);
        },

        async getById(id: string): Promise<ConsumptionEntry> {
            log.debug('consumption.getById', { id });
            return driver.queryOne<ConsumptionEntry>(`SELECT ${COLUMNS} FROM consumption_entries WHERE id = ?`, [id], {
                notFound: () => new NotFoundError(`Consumption entry ${id} not found`),
            });
        },

        async getByDate(date: string): Promise<ConsumptionEntry[]> {
            log.debug('consumption.getByDate', { date });
            return driver.query<ConsumptionEntry>(
                `SELECT ${COLUMNS} FROM consumption_entries WHERE date = ? ORDER BY meal_type, created_at`,
                date,
            );
        },

        async getByDateRange(from: string, to: string): Promise<ConsumptionEntry[]> {
            log.debug('consumption.getByDateRange', { from, to });
            return driver.query<ConsumptionEntry>(
                `SELECT ${COLUMNS} FROM consumption_entries WHERE date >= ? AND date <= ? ORDER BY date DESC, meal_type, created_at`,
                from,
                to,
            );
        },

        async getDateRangeSummary(from: string, to: string): Promise<DailyNutritionSummary[]> {
            log.debug('consumption.getDateRangeSummary', { from, to });
            return driver.query<DailyNutritionSummary>(
                `
                    SELECT date,
                           COALESCE(SUM(calories), 0) AS total_calories,
                           COALESCE(SUM(protein_g), 0) AS total_protein_g,
                           COALESCE(SUM(carbs_g), 0) AS total_carbs_g,
                           COALESCE(SUM(fat_g), 0) AS total_fat_g,
                           COALESCE(SUM(fiber_g), 0) AS total_fiber_g,
                           COUNT(*) AS entry_count
                    FROM consumption_entries
                    WHERE date >= ? AND date <= ?
                    GROUP BY date
                    ORDER BY date DESC
                `,
                from,
                to,
            );
        },

        async create(entry: NewConsumptionEntry): Promise<ConsumptionEntry> {
            log.debug('consumption.create: BEGIN', { date: entry.date, foodItemId: entry.food_item_id });
            await driver.execute('BEGIN TRANSACTION');
            try {
                const id = await insertConsumptionEntryAndRecompute(driver, entry);
                await driver.execute('COMMIT');
                log.debug('consumption.create: COMMIT', { id });
                return repository.getById(id);
            } catch (err) {
                await driver.execute('ROLLBACK');
                log.warn('consumption.create: ROLLBACK', { error: err instanceof Error ? err.message : String(err) });
                throw err;
            }
        },

        /**
         * Convenience: insert by food_item_id + amount, snapshotting macros from
         * the referenced food item. Caller passes the macros explicitly to override
         * (e.g. "I had less butter").
         */
        async createForFoodItem(
            foodItem: FoodItem,
            payload: { date: string; meal_type: NewConsumptionEntry['meal_type']; amount: number; overrides?: Partial<NewConsumptionEntry> },
        ): Promise<ConsumptionEntry> {
            const snapshot = computeSnapshotMacros(foodItem, payload.amount);
            return repository.create({
                date: payload.date,
                meal_type: payload.meal_type,
                food_item_id: foodItem.id,
                amount: payload.amount,
                calories: payload.overrides?.calories ?? snapshot.calories ?? undefined,
                protein_g: payload.overrides?.protein_g ?? snapshot.protein_g ?? undefined,
                carbs_g: payload.overrides?.carbs_g ?? snapshot.carbs_g ?? undefined,
                fat_g: payload.overrides?.fat_g ?? snapshot.fat_g ?? undefined,
                fiber_g: payload.overrides?.fiber_g ?? snapshot.fiber_g ?? undefined,
                sugar_g: payload.overrides?.sugar_g ?? snapshot.sugar_g ?? undefined,
                sodium_mg: payload.overrides?.sodium_mg ?? snapshot.sodium_mg ?? undefined,
                source_meal_id: payload.overrides?.source_meal_id,
                meal_occurrence_id: payload.overrides?.meal_occurrence_id,
                consumed_at: payload.overrides?.consumed_at,
            });
        },

        async update(id: string, updates: Partial<NewConsumptionEntry>): Promise<ConsumptionEntry> {
            const existing = await repository.getById(id);
            log.debug('consumption.update', { id, fields: Object.keys(updates) });

            const fields: string[] = [];
            const values: unknown[] = [];

            const allowed = [
                'date', 'meal_type', 'food_item_id', 'amount',
                'calories', 'protein_g', 'carbs_g', 'fat_g', 'fiber_g', 'sugar_g', 'sodium_mg',
                'source_meal_id', 'meal_occurrence_id', 'consumed_at',
            ] as const;

            for (const field of allowed) {
                if (updates[field] !== undefined) {
                    fields.push(`${field} = ?`);
                    values.push(updates[field] ?? null);
                }
            }

            if (fields.length === 0) return existing;

            fields.push("updated_at = datetime('now')");
            values.push(id);

            const newFoodItemId = (updates.food_item_id ?? existing.food_item_id);
            const amountChanged = 'amount' in updates && updates.amount !== existing.amount;
            const foodItemChanged = newFoodItemId !== existing.food_item_id;

            log.debug('consumption.update: BEGIN', { id });
            await driver.execute('BEGIN TRANSACTION');
            try {
                await driver.execute(`UPDATE consumption_entries SET ${fields.join(', ')} WHERE id = ?`, ...values);
                if (amountChanged || foodItemChanged) {
                    await recomputeDefaultServingAmount(driver, newFoodItemId);
                    if (foodItemChanged) {
                        await recomputeDefaultServingAmount(driver, existing.food_item_id);
                    }
                }
                await driver.execute('COMMIT');
                log.debug('consumption.update: COMMIT', { id });
            } catch (err) {
                await driver.execute('ROLLBACK');
                log.warn('consumption.update: ROLLBACK', { id, error: err instanceof Error ? err.message : String(err) });
                throw err;
            }
            return repository.getById(id);
        },

        async delete(id: string): Promise<boolean> {
            const existing = await repository.findById(id);
            if (!existing) return false;
            log.debug('consumption.delete: BEGIN', { id });
            await driver.execute('BEGIN TRANSACTION');
            try {
                await driver.execute('DELETE FROM consumption_entries WHERE id = ?', id);
                await recomputeDefaultServingAmount(driver, existing.food_item_id);
                await driver.execute('COMMIT');
                log.debug('consumption.delete: COMMIT', { id });
            } catch (err) {
                await driver.execute('ROLLBACK');
                log.warn('consumption.delete: ROLLBACK', { id, error: err instanceof Error ? err.message : String(err) });
                throw err;
            }
            return true;
        },

        // --- Occurrence-group operations (story 255) ---
        // A logged "meal" is the set of entries sharing one `meal_occurrence_id`
        // (created by one meal-template log / accepted AI estimate). These act on
        // the whole group atomically so the user can rescale / move / delete a
        // dish without hand-editing every ingredient.

        async getByOccurrenceId(occurrenceId: string): Promise<ConsumptionEntry[]> {
            log.debug('consumption.getByOccurrenceId', { occurrenceId });
            return driver.query<ConsumptionEntry>(
                `SELECT ${COLUMNS} FROM consumption_entries WHERE meal_occurrence_id = ? ORDER BY rowid`,
                occurrenceId,
            );
        },

        /**
         * Multiply the portion of every entry in the group by `factor`. Both the
         * `amount` and the seven snapshot macro columns scale linearly — the stored
         * macros are point-in-time snapshots (possibly overridden), so re-deriving
         * from the food item would discard those overrides; a uniform multiply
         * preserves them. `NULL * factor` stays `NULL`, so "unknown" nutrients stay
         * unknown. Relative, not absolute: applying ×1.5 twice yields ×2.25.
         * Recomputes `default_serving_amount` for each affected food item.
         */
        async scaleOccurrence(occurrenceId: string, factor: number): Promise<ConsumptionEntry[]> {
            if (!Number.isFinite(factor) || factor <= 0) {
                throw new Error(`scaleOccurrence: factor must be a positive finite number, got ${factor}`);
            }
            const entries = await repository.getByOccurrenceId(occurrenceId);
            if (entries.length === 0) return [];
            const foodItemIds = [...new Set(entries.map((e) => e.food_item_id))];
            log.debug('consumption.scaleOccurrence: BEGIN', { occurrenceId, factor, count: entries.length });
            await driver.execute('BEGIN TRANSACTION');
            try {
                await driver.execute(
                    `UPDATE consumption_entries SET
                        amount = amount * ?,
                        calories = calories * ?,
                        protein_g = protein_g * ?,
                        carbs_g = carbs_g * ?,
                        fat_g = fat_g * ?,
                        fiber_g = fiber_g * ?,
                        sugar_g = sugar_g * ?,
                        sodium_mg = sodium_mg * ?,
                        updated_at = datetime('now')
                     WHERE meal_occurrence_id = ?`,
                    factor, factor, factor, factor, factor, factor, factor, factor,
                    occurrenceId,
                );
                for (const foodItemId of foodItemIds) {
                    await recomputeDefaultServingAmount(driver, foodItemId);
                }
                await driver.execute('COMMIT');
                log.debug('consumption.scaleOccurrence: COMMIT', { occurrenceId });
            } catch (err) {
                await driver.execute('ROLLBACK');
                log.warn('consumption.scaleOccurrence: ROLLBACK', { occurrenceId, error: err instanceof Error ? err.message : String(err) });
                throw err;
            }
            return repository.getByOccurrenceId(occurrenceId);
        },

        /**
         * Move the whole group to a different date and/or meal slot. Amounts are
         * untouched, so `default_serving_amount` needs no recompute.
         *
         * Story 260: a date move keeps the time-of-day component of stamped
         * entries — the eaten-at wall-clock time in `timeZone` is re-anchored
         * on the new date (so a 19:00 dinner stays a 19:00 dinner across a DST
         * boundary). Unstamped entries stay unstamped. `timeZone` comes from
         * the client that rendered the time; absent/invalid falls back to the
         * app default via `resolveAppTimeZone`.
         */
        async moveOccurrence(
            occurrenceId: string,
            updates: { date?: string; meal_type?: NewConsumptionEntry['meal_type']; timeZone?: string },
        ): Promise<ConsumptionEntry[]> {
            const fields: string[] = [];
            const values: unknown[] = [];
            if (updates.date !== undefined) {
                fields.push('date = ?');
                values.push(updates.date);
            }
            if (updates.meal_type !== undefined) {
                fields.push('meal_type = ?');
                values.push(updates.meal_type);
            }
            if (fields.length === 0) return repository.getByOccurrenceId(occurrenceId);

            const stamped = updates.date !== undefined
                ? (await repository.getByOccurrenceId(occurrenceId)).filter((e) => e.consumed_at != null)
                : [];

            fields.push("updated_at = datetime('now')");
            values.push(occurrenceId);
            log.debug('consumption.moveOccurrence: BEGIN', { occurrenceId, fields: Object.keys(updates) });
            await driver.execute('BEGIN TRANSACTION');
            try {
                await driver.execute(
                    `UPDATE consumption_entries SET ${fields.join(', ')} WHERE meal_occurrence_id = ?`,
                    ...values,
                );
                if (stamped.length > 0) {
                    const zone = resolveAppTimeZone(updates.timeZone);
                    const newDate = Temporal.PlainDate.from(updates.date!);
                    for (const entry of stamped) {
                        const wallClock = Temporal.Instant.from(entry.consumed_at!)
                            .toZonedDateTimeISO(zone)
                            .toPlainTime();
                        const shifted = newDate
                            .toZonedDateTime({ timeZone: zone, plainTime: wallClock })
                            .toInstant()
                            .toString();
                        await driver.execute(
                            'UPDATE consumption_entries SET consumed_at = ? WHERE id = ?',
                            shifted,
                            entry.id,
                        );
                    }
                }
                await driver.execute('COMMIT');
                log.debug('consumption.moveOccurrence: COMMIT', { occurrenceId });
            } catch (err) {
                await driver.execute('ROLLBACK');
                log.warn('consumption.moveOccurrence: ROLLBACK', { occurrenceId, error: err instanceof Error ? err.message : String(err) });
                throw err;
            }
            return repository.getByOccurrenceId(occurrenceId);
        },

        /** Delete every entry in the group; recompute defaults for affected food items. Returns the count deleted. */
        async deleteOccurrence(occurrenceId: string): Promise<number> {
            const entries = await repository.getByOccurrenceId(occurrenceId);
            if (entries.length === 0) return 0;
            const foodItemIds = [...new Set(entries.map((e) => e.food_item_id))];
            log.debug('consumption.deleteOccurrence: BEGIN', { occurrenceId, count: entries.length });
            await driver.execute('BEGIN TRANSACTION');
            try {
                await driver.execute('DELETE FROM consumption_entries WHERE meal_occurrence_id = ?', occurrenceId);
                for (const foodItemId of foodItemIds) {
                    await recomputeDefaultServingAmount(driver, foodItemId);
                }
                await driver.execute('COMMIT');
                log.debug('consumption.deleteOccurrence: COMMIT', { occurrenceId });
            } catch (err) {
                await driver.execute('ROLLBACK');
                log.warn('consumption.deleteOccurrence: ROLLBACK', { occurrenceId, error: err instanceof Error ? err.message : String(err) });
                throw err;
            }
            return entries.length;
        },
    };

    return repository;
}

export type ConsumptionRepository = ReturnType<typeof createConsumptionRepository>;
